[asy]
unitsize(0.5 cm);

import geometry; defaultpen(linewidth(.8)+fontsize(10));
label("$O_1$",(0,4),W); label("$O_2$",(0,0),SW); label("$B$",(6,0),SE); label("$A$",(3,4),NE);
