draw(scale(1,.2)*arc((0,0),6,0,180),linetype("2 4"));
draw(scale(1,.2)*arc((0,0),6,180,360));
draw(scale(1,.2)*arc((0,20),3,0,180));
draw(scale(1,.2)*arc((0,20),3,180,360));
